import { useEffect, useState } from 'react';
import api from '../../services/api';
import ProductoForm from './ProductoForm';
import toast from 'react-hot-toast';

export default function ProductoList() {
  const [productos, setProductos] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editingProducto, setEditingProducto] = useState(null);
  const [termino, setTermino] = useState('');
  const [loading, setLoading] = useState(true);

  const fetchProductos = async () => {
    try {
      const res = await api.get('/productos');
      setProductos(res.data);
    } catch (error) {
      toast.error('Error al cargar productos');
    } finally {
      setLoading(false);
    }
  };

  const buscarProductos = async () => {
    if (!termino.trim()) return fetchProductos();
    try {
      const res = await api.get(`/productos/buscar?termino=${termino}`);
      setProductos(res.data);
    } catch (error) {
      toast.error('Error en búsqueda');
    }
  };

  useEffect(() => {
    fetchProductos();
  }, []);

  const handleToggleActivo = async (id, activoActual) => {
    try {
      await api.patch(`/productos/${id}/toggle-activo`, { activo: !activoActual });
      toast.success(`Producto ${!activoActual ? 'activado' : 'desactivado'}`);
      fetchProductos();
    } catch (error) {
      toast.error('Error al cambiar estado');
    }
  };

  const handleEdit = (producto) => {
    setEditingProducto(producto);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('¿Eliminar producto permanentemente?')) {
      try {
        await api.delete(`/productos/${id}`);
        toast.success('Producto eliminado');
        fetchProductos();
      } catch (error) {
        toast.error('Error al eliminar');
      }
    }
  };

  const handleFormClose = () => {
    setShowForm(false);
    setEditingProducto(null);
    fetchProductos();
  };

  if (loading) return <div>Cargando...</div>;

  return (
    <div>
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-2xl font-bold">Productos</h1>
        <button onClick={() => setShowForm(true)} className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700">
          Nuevo Producto
        </button>
      </div>
      <div className="mb-4 flex gap-2">
        <input
          type="text"
          placeholder="Buscar por nombre o código"
          value={termino}
          onChange={e => setTermino(e.target.value)}
          className="border p-2 rounded flex-1"
        />
        <button onClick={buscarProductos} className="bg-blue-500 text-white px-4 py-2 rounded">Buscar</button>
        <button onClick={fetchProductos} className="bg-gray-500 text-white px-4 py-2 rounded">Limpiar</button>
      </div>
      <div className="overflow-x-auto">
        <table className="min-w-full bg-white border">
          <thead>
            <tr className="bg-gray-100">
              <th className="py-2 px-4 border">Código</th>
              <th className="py-2 px-4 border">Nombre</th>
              <th className="py-2 px-4 border">P. Venta</th>
              <th className="py-2 px-4 border">Stock</th>
              <th className="py-2 px-4 border">Estado</th>
              <th className="py-2 px-4 border">Acciones</th>
             </tr>
          </thead>
          <tbody>
            {productos.map(p => (
              <tr key={p.id} className="hover:bg-gray-50">
                <td className="py-2 px-4 border">{p.codigo}</td>
                <td className="py-2 px-4 border">{p.nombre}</td>
                <td className="py-2 px-4 border">${p.precio_venta}</td>
                <td className="py-2 px-4 border">{p.stock_actual}</td>
                <td className="py-2 px-4 border">{p.activo ? 'Activo' : 'Inactivo'}</td>
                <td className="py-2 px-4 border">
                  <button onClick={() => handleEdit(p)} className="text-blue-600 mr-2">Editar</button>
                  <button onClick={() => handleToggleActivo(p.id, p.activo)} className="text-yellow-600 mr-2">
                    {p.activo ? 'Desactivar' : 'Activar'}
                  </button>
                  <button onClick={() => handleDelete(p.id)} className="text-red-600">Eliminar</button>
                 </td>
               </tr>
            ))}
          </tbody>
         </table>
      </div>
      {showForm && (
        <ProductoForm producto={editingProducto} onClose={handleFormClose} />
      )}
    </div>
  );
}
